const amqp = require('amqplib');

async function startConsumer() {
  try {
    // Connect to RabbitMQ server
    const connection = await amqp.connect('amqp://localhost');
    const channel = await connection.createChannel();

    // Declare the queue from which messages will be consumed
    const queue = 'payment_events';
    await channel.assertQueue(queue, { durable: true });

    console.log(`Waiting for messages in ${queue}. To exit press CTRL+C`);

    // Define the payment processing logic
    function processPayment(event) {
      // Extract payment details from event message
      const { amount, currency, customerID } = JSON.parse(event);

      // Execute payment logic here
      console.log(`Processing payment of ${amount} ${currency} for customer ${customerID}`);
      // Payment processing code...
    }

    // Consume messages from the queue
    channel.consume(queue, (msg) => {
      if (msg !== null) {
        processPayment(msg.content.toString());
        channel.ack(msg); // Acknowledge the message after processing
      }
    });
  } catch (error) {
    console.error('Error connecting to RabbitMQ:', error);
  }
}

// Start the consumer
startConsumer();